@ StrutsTag ( name = "bind" , tldTagClass = "org.apache.struts2.dojo.views.jsp.ui.BindTag" , description = "Attach event listeners to elements to make AJAX calls" ) @ StrutsTagSkipInheritance public class Bind extends AbstractValidateBean { public static final String TEMPLATE = "bind-close" ; public static final String OPEN_TEMPLATE = "bind" ; protected String targets ; protected String sources ; protected String events ; public Bind ( ValueStack stack , HttpServletRequest request , HttpServletResponse response ) { super ( stack , request , response ) ; } public String getDefaultOpenTemplate ( ) { return OPEN_TEMPLATE ; } protected String getDefaultTemplate ( ) { return TEMPLATE ; } public void evaluateExtraParams ( ) { super . evaluateExtraParams ( ) ; if ( targets != null ) addParameter ( "targets" , findString ( targets ) ) ; if ( sources != null ) addParameter ( "sources" , findString ( sources ) ) ; if ( events != null ) addParameter ( "events" , findString ( events ) ) ; } @ StrutsTagAttribute ( description = "Comma delimited list of event names to attach to" ) public void setEvents ( String events ) { this . events = events ; } @ StrutsTagAttribute ( description = "Comma delimited list of ids of the elements to attach to" ) public void setSources ( String sources ) { this . sources = sources ; } @ StrutsTagAttribute ( description = "Comma delimited list of ids of the elements whose content will be updated" ) public void setTargets ( String targets ) { this . targets = targets ; } @ Override @ StrutsTagSkipInheritance public void setTheme ( String theme ) { super . setTheme ( theme ) ; } @ Override public String getTheme ( ) { return "ajax" ; } @ StrutsTagAttribute ( description = "Topic that will trigger the remote call" ) public void setListenTopics ( String listenTopics ) { this . listenTopics = listenTopics ; } @ StrutsTagAttribute ( description = "The URL to call to obtain the content. Note: If used with ajax context, the value must be set as an url tag value." ) public void setHref ( String href ) { this . href = href ; } @ StrutsTagAttribute ( description = "The text to display to the user if the is an error fetching the content" ) public void setErrorText ( String errorText ) { this . errorText = errorText ; } @ StrutsTagAttribute ( description = "Javascript code in the fetched content will be executed" , type = "Boolean" , defaultValue = "false" ) public void setExecuteScripts ( String executeScripts ) { this . executeScripts = executeScripts ; } @ StrutsTagAttribute ( description = "Text to be shown while content is being fetched" , defaultValue = "Loading..." ) public void setLoadingText ( String loadingText ) { this . loadingText = loadingText ; } @ StrutsTagAttribute ( description = "Javascript function name that will make the request" ) public void setHandler ( String handler ) { this . handler = handler ; } @ StrutsTagAttribute ( description = "Function name used to filter the fields of the form." ) public void setFormFilter ( String formFilter ) { this . formFilter = formFilter ; } @ StrutsTagAttribute ( description = "Form id whose fields will be serialized and passed as parameters" ) public void setFormId ( String formId ) { this . formId = formId ; } @ StrutsTagAttribute ( description = "Comma delimmited list of topics that will published before and after the request, and on errors" ) public void setNotifyTopics ( String notifyTopics ) { this . notifyTopics = notifyTopics ; } @ StrutsTagAttribute ( description = "Set whether errors will be shown or not" , type = "Boolean" , defaultValue = "true" ) public void setShowErrorTransportText ( String showError ) { this . showErrorTransportText = showError ; } @ StrutsTagAttribute ( description = "Id of element that will be shown while making request" ) public void setIndicator ( String indicator ) { this . indicator = indicator ; } @ StrutsTagAttribute ( description = "Show loading text on targets" , type = "Boolean" , defaultValue = "false" ) public void setShowLoadingText ( String showLoadingText ) { this . showLoadingText = showLoadingText ; } @ StrutsTagSkipInheritance public void setCssClass ( String cssClass ) { super . setCssClass ( cssClass ) ; } @ StrutsTagSkipInheritance public void setCssStyle ( String cssStyle ) { super . setCssStyle ( cssStyle ) ; } @ StrutsTagSkipInheritance public void setName ( String name ) { super . setName ( name ) ; } @ StrutsTagAttribute ( description = "Comma delimmited list of topics that will published after the request(if the request succeeds)" ) public void setAfterNotifyTopics ( String afterNotifyTopics ) { this . afterNotifyTopics = afterNotifyTopics ; } @ StrutsTagAttribute ( description = "Comma delimmited list of topics that will published before the request" ) public void setBeforeNotifyTopics ( String beforeNotifyTopics ) { this . beforeNotifyTopics = beforeNotifyTopics ; } @ StrutsTagAttribute ( description = "Comma delimmited list of topics that will published after the request(if the request fails)" ) public void setErrorNotifyTopics ( String errorNotifyTopics ) { this . errorNotifyTopics = errorNotifyTopics ; } @ StrutsTagAttribute ( description = "The id to use for the element" ) public void setId ( String id ) { super . setId ( id ) ; } @ StrutsTagAttribute ( description = "Color used to perform a highlight effect on the elements specified in the 'targets' attribute" , defaultValue = "none" ) public void setHighlightColor ( String highlightColor ) { this . highlightColor = highlightColor ; } @ StrutsTagAttribute ( description = "Duration of highlight effect in milliseconds. Only valid if 'highlightColor' attribute is set" , defaultValue = "2000" , type = "Integer" ) public void setHighlightDuration ( String highlightDuration ) { this . highlightDuration = highlightDuration ; } @ StrutsTagAttribute ( description = "Perform Ajax validation. 'ajaxValidation' interceptor must be applied to action" , type = "Boolean" , defaultValue = "false" ) public void setValidate ( String validate ) { this . validate = validate ; } @ StrutsTagAttribute ( description = "Make an asynchronous request if validation succeeds. Only valid is 'validate' is 'true'" , type = "Boolean" , defaultValue = "false" ) public void setAjaxAfterValidation ( String ajaxAfterValidation ) { this . ajaxAfterValidation = ajaxAfterValidation ; } @ StrutsTagAttribute ( description = "Run scripts in a separate scope, unique for each tag" , defaultValue = "true" ) public void setSeparateScripts ( String separateScripts ) { this . separateScripts = separateScripts ; } @ StrutsTagAttribute ( description = "Transport used by Dojo to make the request" , defaultValue = "XMLHTTPTransport" ) public void setTransport ( String transport ) { this . transport = transport ; } }